#include <bits/stdc++.h>
using namespace std;
int main()
{
    string a,b;
    int n,c,d,e,h=-1,l,c1,d1,e1;
    cin>>n;
    for(int i=0;i<n;i++)
    {
        cin>>b>>c>>d>>e;
        l=c+d+e;
        if(l>h)
        {
            h=l;
            a=b;
            c1=c;
            d1=d;
            e1=e;
        }
    }
    cout<<a<<' '<<c1<<' '<<d1<<' '<<e1<<' ';
    return 0;
}
